  1→/*
  2→ * compare_state_logs.c - Offline comparison of two state log files
  3→ *
  4→ * Compares per-frame game state dumps produced by the input replayer
  5→ * running through two different builds (e.g., C-only vs OCaml bridge).
  6→ *
  7→ * Usage: compare_state_logs <log_a.bin> <log_b.bin>
  8→ *
  9→ * State log format per frame:
 10→ *   uint32_t frame_number
 11→ *   int32_t  n_objects
 12→ *   object   objects[n_objects]
 13→ *   ai_local ai_local_info[n_objects]
 14→ *   player   players[MAX_PLAYERS]
 15→ *   int32_t  globals[5]  (Player_is_dead, Player_exploded, Overall_agitation,
 16→ *                         Highest_object_index, rand_state)
 17→ */
 18→
 19→#include <stdio.h>
 20→#include <stdlib.h>
 21→#include <string.h>
 22→#include <stdint.h>
 23→
 24→/* We don't include game headers here - we compare raw bytes.
 25→ * Object and struct sizes are detected from the log files. */
 26→
 27→#define MAX_OBJECTS 350
 28→#define MAX_PLAYERS 8
 29→
 30→static int verbose = 0;
 31→
 32→typedef struct {
 33→	uint32_t frame;
 34→	int32_t  n_objects;
 35→	int32_t  globals[5];
 36→	/* Raw bytes for objects, ai_local, players follow */
 37→	uint8_t  *object_data;      /* n_objects * object_size */
 38→	uint8_t  *ai_local_data;    /* n_objects * ai_local_size */
 39→	uint8_t  *player_data;      /* MAX_PLAYERS * player_size */
 40→} frame_state;
 41→
 42→/*
 43→ * Read one frame from the state log.
 44→ * Returns bytes of object/ai data read, or -1 on EOF/error.
 45→ * Caller must free object_data, ai_local_data, player_data.
 46→ */
 47→static int read_frame(FILE *f, frame_state *state,
 48→                      size_t object_size, size_t ai_local_size, size_t player_size)
 49→{
 50→	if (fread(&state->frame, sizeof(uint32_t), 1, f) != 1)
 51→		return -1;
 52→
 53→	if (fread(&state->n_objects, sizeof(int32_t), 1, f) != 1)
 54→		return -1;
 55→
 56→	if (state->n_objects < 0 || state->n_objects > MAX_OBJECTS) {
 57→		fprintf(stderr, "ERROR: invalid n_objects %d at frame %u\n",
 58→			state->n_objects, state->frame);
 59→		return -1;
 60→	}
 61→
 62→	size_t obj_bytes = state->n_objects * object_size;
 63→	size_t ai_bytes = state->n_objects * ai_local_size;
 64→	size_t player_bytes = MAX_PLAYERS * player_size;
 65→
 66→	state->object_data = NULL;
 67→	state->ai_local_data = NULL;
 68→	state->player_data = NULL;
 69→
 70→	if (obj_bytes > 0) {
 71→		state->object_data = (uint8_t *)malloc(obj_bytes);
 72→		if (fread(state->object_data, 1, obj_bytes, f) != obj_bytes)
 73→			return -1;
 74→	}
 75→
 76→	if (ai_bytes > 0) {
 77→		state->ai_local_data = (uint8_t *)malloc(ai_bytes);
 78→		if (fread(state->ai_local_data, 1, ai_bytes, f) != ai_bytes)
 79→			return -1;
 80→	}
 81→
 82→	state->player_data = (uint8_t *)malloc(player_bytes);
 83→	if (fread(state->player_data, 1, player_bytes, f) != player_bytes)
 84→		return -1;
 85→
 86→	if (fread(state->globals, sizeof(state->globals), 1, f) != 1)
 87→		return -1;
 88→
 89→	return 0;
 90→}
 91→
 92→static void free_frame(frame_state *state)
 93→{
 94→	free(state->object_data);
 95→	free(state->ai_local_data);
 96→	free(state->player_data);
 97→	state->object_data = NULL;
 98→	state->ai_local_data = NULL;
 99→	state->player_data = NULL;
100→}
101→
102→static int compare_bytes(const uint8_t *a, const uint8_t *b, size_t len,
103→                         const char *label, uint32_t frame, int index)
104→{
105→	int diffs = 0;
106→	for (size_t i = 0; i < len; i++) {
107→		if (a[i] != b[i]) {
108→			diffs++;
109→			if (verbose && diffs <= 10) {
110→				if (index >= 0)
111→					printf("  frame=%u %s[%d] byte %zu: A=0x%02X B=0x%02X\n",
112→						frame, label, index, i, a[i], b[i]);
113→				else
114→					printf("  frame=%u %s byte %zu: A=0x%02X B=0x%02X\n",
115→						frame, label, i, a[i], b[i]);
116→			}
117→		}
118→	}
119→	return diffs;
120→}
121→
122→int main(int argc, char **argv)
123→{
124→	if (argc < 3) {
125→		fprintf(stderr, "Usage: %s [-v] <log_a.bin> <log_b.bin> [object_size] [ai_local_size] [player_size]\n", argv[0]);
126→		fprintf(stderr, "\nCompare two state log files frame-by-frame.\n");
127→		fprintf(stderr, "Optional size args default to common Descent 2 struct sizes.\n");
128→		fprintf(stderr, "Use -v for verbose byte-level diff output.\n");
129→		return 1;
130→	}
131→
132→	int arg_offset = 1;
133→	if (strcmp(argv[1], "-v") == 0) {
134→		verbose = 1;
135→		arg_offset = 2;
136→	}
137→
138→	const char *file_a = argv[arg_offset];
139→	const char *file_b = argv[arg_offset + 1];
140→
141→	/* Default struct sizes for Descent 2 on arm64 macOS */
142→	size_t object_size = (argc > arg_offset + 2) ? (size_t)atoi(argv[arg_offset + 2]) : 268;
143→	size_t ai_local_size = (argc > arg_offset + 3) ? (size_t)atoi(argv[arg_offset + 3]) : 200;
144→	size_t player_size = (argc > arg_offset + 4) ? (size_t)atoi(argv[arg_offset + 4]) : 148;
145→
146→	FILE *fa = fopen(file_a, "rb");
147→	FILE *fb = fopen(file_b, "rb");
148→
149→	if (!fa) { fprintf(stderr, "ERROR: cannot open '%s'\n", file_a); return 1; }
150→	if (!fb) { fprintf(stderr, "ERROR: cannot open '%s'\n", file_b); fclose(fa); return 1; }

  1→/*
  2→ * dump_obj_state.c - Dump specific object fields from a state log at given frames
  3→ *
  4→ * Usage: dump_obj_state <log.bin> <obj_index> <start_frame> <end_frame>
  5→ *
  6→ * Prints position, velocity, thrust, rotvel, orientation, segment, type, mode
  7→ * for the given object at each frame in the range.
  8→ */
  9→
 10→#include <stdio.h>
 11→#include <stdlib.h>
 12→#include <stdint.h>
 13→#include <string.h>
 14→
 15→#define MAX_OBJECTS 350
 16→#define MAX_PLAYERS 8
 17→
 18→/* arm64 macOS struct sizes */
 19→#define OBJECT_SIZE 268
 20→#define AI_LOCAL_SIZE 200
 21→#define PLAYER_SIZE 148
 22→
 23→/* Read a 32-bit signed int from a byte offset in the object data */
 24→static int32_t read_i32(const uint8_t *data, size_t offset) {
 25→	int32_t v;
 26→	memcpy(&v, data + offset, 4);
 27→	return v;
 28→}
 29→
 30→static int16_t read_i16(const uint8_t *data, size_t offset) {
 31→	int16_t v;
 32→	memcpy(&v, data + offset, 2);
 33→	return v;
 34→}
 35→
 36→static uint8_t read_u8(const uint8_t *data, size_t offset) {
 37→	return data[offset];
 38→}
 39→
 40→int main(int argc, char **argv) {
 41→	if (argc < 5) {
 42→		fprintf(stderr, "Usage: %s <log.bin> <obj_index> <start_frame> <end_frame>\n", argv[0]);
 43→		return 1;
 44→	}
 45→
 46→	const char *filename = argv[1];
 47→	int obj_idx = atoi(argv[2]);
 48→	int start_frame = atoi(argv[3]);
 49→	int end_frame = atoi(argv[4]);
 50→
 51→	FILE *f = fopen(filename, "rb");
 52→	if (!f) { fprintf(stderr, "Cannot open %s\n", filename); return 1; }
 53→
 54→	while (1) {
 55→		uint32_t frame;
 56→		int32_t n_objects;
 57→
 58→		if (fread(&frame, 4, 1, f) != 1) break;
 59→		if (fread(&n_objects, 4, 1, f) != 1) break;
 60→
 61→		if (n_objects < 0 || n_objects > MAX_OBJECTS) {
 62→			fprintf(stderr, "Bad n_objects %d at frame %u\n", n_objects, frame);
 63→			break;
 64→		}
 65→
 66→		size_t obj_bytes = n_objects * OBJECT_SIZE;
 67→		size_t ai_bytes = n_objects * AI_LOCAL_SIZE;
 68→		size_t player_bytes = MAX_PLAYERS * PLAYER_SIZE;
 69→		size_t globals_bytes = 5 * 4;
 70→
 71→		uint8_t *obj_data = malloc(obj_bytes);
 72→		uint8_t *ai_data = malloc(ai_bytes);
 73→		uint8_t *player_data = malloc(player_bytes);
 74→		int32_t globals[5];
 75→
 76→		if (fread(obj_data, 1, obj_bytes, f) != obj_bytes) { free(obj_data); free(ai_data); free(player_data); break; }
 77→		if (fread(ai_data, 1, ai_bytes, f) != ai_bytes) { free(obj_data); free(ai_data); free(player_data); break; }
 78→		if (fread(player_data, 1, player_bytes, f) != player_bytes) { free(obj_data); free(ai_data); free(player_data); break; }
 79→		if (fread(globals, 1, globals_bytes, f) != globals_bytes) { free(obj_data); free(ai_data); free(player_data); break; }
 80→
 81→		if ((int)frame >= start_frame && (int)frame <= end_frame && obj_idx < n_objects) {
 82→			const uint8_t *obj = obj_data + obj_idx * OBJECT_SIZE;
 83→			const uint8_t *ai = ai_data + obj_idx * AI_LOCAL_SIZE;
 84→
 85→			printf("=== Frame %u, Object %d ===\n", frame, obj_idx);
 86→			printf("  type=%d id=%d control=%d movement=%d render=%d flags=0x%02X\n",
 87→				read_u8(obj, 4), read_u8(obj, 5), read_u8(obj, 10), read_u8(obj, 11),
 88→				read_u8(obj, 12), read_u8(obj, 13));
 89→			printf("  segnum=%d\n", read_i16(obj, 14));
 90→			printf("  pos=(%d, %d, %d)\n",
 91→				read_i32(obj, 20), read_i32(obj, 24), read_i32(obj, 28));
 92→			printf("  last_pos=(%d, %d, %d)\n",
 93→				read_i32(obj, 76), read_i32(obj, 80), read_i32(obj, 84));
 94→			printf("  orient.fvec=(%d, %d, %d)\n",
 95→				read_i32(obj, 56), read_i32(obj, 60), read_i32(obj, 64));
 96→			printf("  size=%d shields=%d\n", read_i32(obj, 68), read_i32(obj, 72));
 97→			printf("  velocity=(%d, %d, %d)\n",
 98→				read_i32(obj, 96), read_i32(obj, 100), read_i32(obj, 104));
 99→			printf("  thrust=(%d, %d, %d)\n",
100→				read_i32(obj, 108), read_i32(obj, 112), read_i32(obj, 116));
101→			printf("  rotvel=(%d, %d, %d)\n",
102→				read_i32(obj, 132), read_i32(obj, 136), read_i32(obj, 140));
103→			printf("  rotthrust=(%d, %d, %d)\n",
104→				read_i32(obj, 144), read_i32(obj, 148), read_i32(obj, 152));
105→			printf("  mass=%d drag=%d phys_flags=0x%04X\n",
106→				read_i32(obj, 120), read_i32(obj, 124), (int)read_i16(obj, 158));
107→			/* ai_info (ctype) starts at offset 160 */
108→			printf("  ai: CURRENT_STATE=%d GOAL_STATE=%d behavior=0x%02X\n",
109→				read_u8(obj, 162), read_u8(obj, 163),
110→				read_u8(obj, 160 + 8)); /* behavior is at offset 8 in ai_static */
111→			printf("  ai: hide_segment=%d cur_path_index=%d path_length=%d\n",
112→				read_i16(obj, 160 + 10), read_i16(obj, 160 + 14), read_i16(obj, 160 + 16));
113→			/* ai_local */
114→			printf("  ailp: player_awareness_type=%d mode=%d\n",
115→				read_i32(ai, 0), read_i32(ai, 12));
116→			printf("  ailp: next_action_time=%d player_awareness_time=%d\n",
117→				read_i32(ai, 28), read_i32(ai, 40));
118→			printf("  ailp: time_since_processed=%d previous_visibility=%d\n",
119→				read_i32(ai, 56), read_i32(ai, 4));
120→			printf("  ailp: goal_segment=%d\n", read_i32(ai, 16));
121→			printf("\n");
122→		}
123→
124→		free(obj_data);
125→		free(ai_data);
126→		free(player_data);
127→	}
128→
129→	fclose(f);
130→	return 0;
131→}
